//! Phyle Temporal Depth Field: noise-resolved reconstruction via triton windows.
//!
//! Single-shot depth estimation is structurally incomplete. Information IS the
//! difference relation across three time samples (past, present, future). The
//! second-degree diff (change of change = curvature) is the primary reconstruction
//! signal. Standing waves (low phase variance) are real geometry; noise resolves
//! only when the shell level meets the spectral budget for that noise color.
//!
//! Shell 0 (3 frames): pink noise resolved.
//! Shell 1 (9 frames): brown noise resolved.
//! Shell 2 (27 frames): sub-brown structure.
//! White noise: permanently deferred (truly random, no temporal structure).
//!
//! Deblur integration: the residual deblur (Fano-66-monster architecture) runs
//! per-frame, producing admission masks. The temporal layer then classifies which
//! deblurred edges are stable (standing wave = real edge) vs unstable (noise
//! artifact that single-frame deblur couldn't distinguish from geometry).

use crate::depth_extrusion::DepthError;
use crate::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
use crate::mesh_residual_deblur::{mesh_residual_deblur_rgb_f32, MeshResidualDeblurConfig};

// ─── Constants from Phyle regime ─────────────────────────────────────────────

pub const CLOCK_PERIOD: usize = 3;
pub const PHYLE_BARS: usize = CLOCK_PERIOD * CLOCK_PERIOD;
pub const PHYLE_DIRECTIONS: usize = CLOCK_PERIOD * PHYLE_BARS;
pub const PERFECT_FIFTH_STRIDE: usize = 7;

// ─── Types ───────────────────────────────────────────────────────────────────

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TritonPhase {
    Past,
    Present,
    Future,
}

impl TritonPhase {
    pub fn from_index(i: usize) -> Self {
        match i % CLOCK_PERIOD {
            0 => Self::Past,
            1 => Self::Present,
            _ => Self::Future,
        }
    }

    pub fn index(self) -> usize {
        match self {
            Self::Past => 0,
            Self::Present => 1,
            Self::Future => 2,
        }
    }

    pub fn rotate(self) -> Self {
        match self {
            Self::Past => Self::Present,
            Self::Present => Self::Future,
            Self::Future => Self::Past,
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum NoiseColor {
    White,
    Pink,
    Brown,
    StandingWave,
}

impl NoiseColor {
    pub fn alpha(&self) -> u8 {
        match self {
            Self::White => 0,
            Self::Pink => 1,
            Self::Brown => 2,
            Self::StandingWave => 0,
        }
    }

    pub fn resolves_at_shell(&self) -> Option<u8> {
        match self {
            Self::White => None,
            Self::Pink => Some(0),
            Self::Brown => Some(1),
            Self::StandingWave => Some(0),
        }
    }
}

pub fn spectral_budget(shell: u8) -> u8 {
    shell + 1
}

pub fn noise_admitted_at_shell(color: &NoiseColor, shell: u8) -> bool {
    color.alpha() <= spectral_budget(shell)
}

// ─── Per-cell temporal accumulation ──────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct PhyleTemporalCell {
    pub observations: [f32; CLOCK_PERIOD],
    pub confidence: [f32; CLOCK_PERIOD],
    pub deblur_admission: [f32; CLOCK_PERIOD],
    pub first_degree_diffs: [f32; 2],
    pub second_degree_diff: f32,
    pub phase_variance: f32,
    pub deblur_variance: f32,
    pub noise_color: NoiseColor,
    pub resolved_shell: u8,
    pub fused_depth: f32,
    pub fused_confidence: f32,
}

impl Default for PhyleTemporalCell {
    fn default() -> Self {
        Self::new()
    }
}

impl PhyleTemporalCell {
    pub fn new() -> Self {
        Self {
            observations: [0.0; CLOCK_PERIOD],
            confidence: [0.0; CLOCK_PERIOD],
            deblur_admission: [0.0; CLOCK_PERIOD],
            first_degree_diffs: [0.0; 2],
            second_degree_diff: 0.0,
            phase_variance: 0.0,
            deblur_variance: 0.0,
            noise_color: NoiseColor::White,
            resolved_shell: 0,
            fused_depth: 0.0,
            fused_confidence: 0.0,
        }
    }

    pub fn ingest(&mut self, phase: TritonPhase, depth: f32, confidence: f32, deblur_adm: f32) {
        let i = phase.index();
        self.observations[i] = depth;
        self.confidence[i] = confidence;
        self.deblur_admission[i] = deblur_adm;
    }

    pub fn compute_diffs(&mut self) {
        let d_pp = (self.observations[0] - self.observations[1]).abs();
        let d_pf = (self.observations[1] - self.observations[2]).abs();
        self.first_degree_diffs = [d_pp, d_pf];
        self.second_degree_diff = (d_pp - d_pf).abs();

        let mean = (self.observations[0] + self.observations[1] + self.observations[2]) / 3.0;
        let var = self
            .observations
            .iter()
            .map(|v| (v - mean).powi(2))
            .sum::<f32>()
            / 3.0;
        self.phase_variance = var;

        let dmean =
            (self.deblur_admission[0] + self.deblur_admission[1] + self.deblur_admission[2]) / 3.0;
        let dvar = self
            .deblur_admission
            .iter()
            .map(|v| (v - dmean).powi(2))
            .sum::<f32>()
            / 3.0;
        self.deblur_variance = dvar;
    }

    pub fn classify_noise(&mut self, standing_wave_threshold: f32, deblur_threshold: f32) {
        if self.phase_variance < standing_wave_threshold && self.deblur_variance < deblur_threshold
        {
            self.noise_color = NoiseColor::StandingWave;
        } else if self.phase_variance < standing_wave_threshold * 10.0 {
            self.noise_color = NoiseColor::Pink;
        } else if self.phase_variance < standing_wave_threshold * 100.0 {
            self.noise_color = NoiseColor::Brown;
        } else {
            self.noise_color = NoiseColor::White;
        }
    }

    pub fn try_resolve(&mut self, shell: u8) -> bool {
        if let Some(required) = self.noise_color.resolves_at_shell() {
            if shell >= required {
                let total_conf: f32 = self.confidence.iter().sum();
                if total_conf > 0.0 {
                    self.fused_depth = self
                        .observations
                        .iter()
                        .zip(self.confidence.iter())
                        .map(|(d, c)| d * c)
                        .sum::<f32>()
                        / total_conf;
                    self.fused_confidence = total_conf / CLOCK_PERIOD as f32;
                } else {
                    self.fused_depth = self.observations.iter().sum::<f32>() / CLOCK_PERIOD as f32;
                    self.fused_confidence = 0.0;
                }
                self.resolved_shell = shell;
                return true;
            }
        }
        false
    }
}

// ─── Full temporal depth field ───────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct PhyleTemporalDepthField {
    pub width: u32,
    pub height: u32,
    pub cells: Vec<PhyleTemporalCell>,
    pub triton_windows_completed: u32,
    pub current_shell: u8,
    pub standing_wave_mask: Vec<f32>,
    pub fused_depth: Vec<f32>,
    pub fused_confidence: Vec<f32>,
    pub deblur_stability: Vec<f32>,
    phase_cursor: usize,
}

#[derive(Clone, Debug)]
pub struct TritonWindowResult {
    pub window_index: u32,
    pub shell: u8,
    pub standing_wave_count: u32,
    pub pink_resolved: u32,
    pub brown_resolved: u32,
    pub white_deferred: u32,
    pub rotation_direction: usize,
    pub mean_second_degree_diff: f32,
    pub mean_deblur_stability: f32,
}

impl PhyleTemporalDepthField {
    pub fn new(width: u32, height: u32) -> Self {
        let pix = (width * height) as usize;
        Self {
            width,
            height,
            cells: vec![PhyleTemporalCell::new(); pix],
            triton_windows_completed: 0,
            current_shell: 0,
            standing_wave_mask: vec![0.0; pix],
            fused_depth: vec![0.0; pix],
            fused_confidence: vec![0.0; pix],
            deblur_stability: vec![0.0; pix],
            phase_cursor: 0,
        }
    }

    pub fn current_phase(&self) -> TritonPhase {
        TritonPhase::from_index(self.phase_cursor)
    }

    pub fn rotation_direction(&self) -> usize {
        (self.triton_windows_completed as usize * PERFECT_FIFTH_STRIDE) % PHYLE_DIRECTIONS
    }

    pub fn ingest_frame(
        &mut self,
        depth_values: &[f32],
        depth_confidence: &[f32],
        deblur_admission: &[f32],
    ) -> Result<Option<TritonWindowResult>, DepthError> {
        let pix = (self.width * self.height) as usize;
        if depth_values.len() != pix
            || depth_confidence.len() != pix
            || deblur_admission.len() != pix
        {
            return Err(DepthError::Shape);
        }

        let phase = self.current_phase();

        for i in 0..pix {
            self.cells[i].ingest(
                phase,
                depth_values[i],
                depth_confidence[i],
                deblur_admission[i],
            );
        }

        self.phase_cursor += 1;

        if self.phase_cursor >= CLOCK_PERIOD {
            let result = self.complete_triton_window();
            Ok(Some(result))
        } else {
            Ok(None)
        }
    }

    pub fn ingest_raw_frame(
        &mut self,
        rgb_f32: &[f32],
        depth_config: &MeshDepthConfig,
        deblur_config: &MeshResidualDeblurConfig,
    ) -> Result<Option<TritonWindowResult>, DepthError> {
        let pix = (self.width * self.height) as usize;
        if rgb_f32.len() != pix * 3 {
            return Err(DepthError::Shape);
        }

        let (depth_field, _) =
            build_mesh_depth_field(rgb_f32, self.width, self.height, depth_config, None, None)?;

        let deblur_result =
            mesh_residual_deblur_rgb_f32(rgb_f32, self.width, self.height, deblur_config)?;

        self.ingest_frame(
            &depth_field.values,
            &depth_field.confidence,
            &deblur_result.admission,
        )
    }

    fn complete_triton_window(&mut self) -> TritonWindowResult {
        let pix = (self.width * self.height) as usize;
        let standing_wave_threshold = 0.001;
        let deblur_threshold = 0.01;

        let mut standing_wave_count = 0u32;
        let mut pink_resolved = 0u32;
        let mut brown_resolved = 0u32;
        let mut white_deferred = 0u32;
        let mut sum_second_degree = 0.0f32;
        let mut sum_deblur_stability = 0.0f32;

        let shell = self.current_shell;

        for i in 0..pix {
            let cell = &mut self.cells[i];
            cell.compute_diffs();
            cell.classify_noise(standing_wave_threshold, deblur_threshold);

            sum_second_degree += cell.second_degree_diff;
            sum_deblur_stability += 1.0 - cell.deblur_variance.min(1.0);

            if cell.try_resolve(shell) {
                self.fused_depth[i] = cell.fused_depth;
                self.fused_confidence[i] = cell.fused_confidence;
                self.deblur_stability[i] = 1.0 - cell.deblur_variance.min(1.0);

                match cell.noise_color {
                    NoiseColor::StandingWave => {
                        self.standing_wave_mask[i] = 1.0;
                        standing_wave_count += 1;
                    }
                    NoiseColor::Pink => {
                        self.standing_wave_mask[i] = 0.8;
                        pink_resolved += 1;
                    }
                    NoiseColor::Brown => {
                        self.standing_wave_mask[i] = 0.6;
                        brown_resolved += 1;
                    }
                    _ => {}
                }
            } else {
                if cell.noise_color == NoiseColor::White { white_deferred += 1 }
            }
        }

        let rotation_direction = self.rotation_direction();
        self.triton_windows_completed += 1;
        self.phase_cursor = 0;

        // Promote shell when enough windows accumulated
        let windows_for_next_shell = CLOCK_PERIOD.pow(self.current_shell as u32 + 1) as u32;
        if self.triton_windows_completed >= windows_for_next_shell && self.current_shell < 3 {
            self.current_shell += 1;
        }

        TritonWindowResult {
            window_index: self.triton_windows_completed - 1,
            shell,
            standing_wave_count,
            pink_resolved,
            brown_resolved,
            white_deferred,
            rotation_direction,
            mean_second_degree_diff: sum_second_degree / pix as f32,
            mean_deblur_stability: sum_deblur_stability / pix as f32,
        }
    }

    pub fn standing_wave_coverage(&self) -> f32 {
        let pix = (self.width * self.height) as usize;
        if pix == 0 {
            return 0.0;
        }
        self.standing_wave_mask.iter().filter(|&&v| v > 0.0).count() as f32 / pix as f32
    }

    pub fn frames_at_current_shell(&self) -> usize {
        CLOCK_PERIOD * CLOCK_PERIOD.pow(self.current_shell as u32)
    }

    pub fn total_frames_ingested(&self) -> usize {
        self.triton_windows_completed as usize * CLOCK_PERIOD + self.phase_cursor
    }
}

// ─── Standing wave extraction (depth-specific) ───────────────────────────────

pub struct StandingWaveDepthReport {
    pub confirmed_geometry_pixels: u32,
    pub noise_pixels: u32,
    pub deblur_stable_pixels: u32,
    pub mean_fused_depth: f32,
    pub coverage_ratio: f32,
}

pub fn extract_standing_wave_depth(field: &PhyleTemporalDepthField) -> StandingWaveDepthReport {
    let pix = (field.width * field.height) as usize;
    let mut confirmed = 0u32;
    let mut noise = 0u32;
    let mut deblur_stable = 0u32;
    let mut depth_sum = 0.0f32;

    for i in 0..pix {
        let cell = &field.cells[i];
        match cell.noise_color {
            NoiseColor::StandingWave => {
                confirmed += 1;
                depth_sum += cell.fused_depth;
            }
            NoiseColor::White => noise += 1,
            _ => {}
        }
        if cell.deblur_variance < 0.01 {
            deblur_stable += 1;
        }
    }

    StandingWaveDepthReport {
        confirmed_geometry_pixels: confirmed,
        noise_pixels: noise,
        deblur_stable_pixels: deblur_stable,
        mean_fused_depth: if confirmed > 0 {
            depth_sum / confirmed as f32
        } else {
            0.0
        },
        coverage_ratio: if pix > 0 {
            confirmed as f32 / pix as f32
        } else {
            0.0
        },
    }
}

// ─── Temporal deblur: stability classification ───────────────────────────────

pub struct TemporalDeblurResult {
    pub stable_edges: Vec<f32>,
    pub unstable_noise: Vec<f32>,
    pub edge_confidence: Vec<f32>,
}

pub fn temporal_deblur_classify(field: &PhyleTemporalDepthField) -> TemporalDeblurResult {
    let pix = (field.width * field.height) as usize;
    let mut stable_edges = vec![0.0f32; pix];
    let mut unstable_noise = vec![0.0f32; pix];
    let mut edge_confidence = vec![0.0f32; pix];

    for i in 0..pix {
        let cell = &field.cells[i];
        let deblur_mean =
            (cell.deblur_admission[0] + cell.deblur_admission[1] + cell.deblur_admission[2]) / 3.0;

        if cell.deblur_variance < 0.01 && deblur_mean > 0.3 {
            // Stable high-admission = real edge confirmed across time
            stable_edges[i] = deblur_mean;
            edge_confidence[i] = 1.0 - cell.deblur_variance;
        } else if cell.deblur_variance > 0.05 {
            // High variance in deblur admission = noise artifact
            unstable_noise[i] = cell.deblur_variance;
            edge_confidence[i] = 0.0;
        } else {
            // Intermediate: partially resolved
            stable_edges[i] = deblur_mean * (1.0 - cell.deblur_variance * 10.0).max(0.0);
            edge_confidence[i] = (1.0 - cell.deblur_variance * 10.0).max(0.0);
        }
    }

    TemporalDeblurResult {
        stable_edges,
        unstable_noise,
        edge_confidence,
    }
}

// ─── Up-resolution via constructive interference ─────────────────────────────

pub struct UpresolutionResult {
    pub resolved_depth: Vec<f32>,
    pub resolved_mask: Vec<bool>,
    pub resolution_gain: f32,
}

pub fn upresolution_step(field: &PhyleTemporalDepthField) -> UpresolutionResult {
    let pix = (field.width * field.height) as usize;
    let mut resolved_depth = vec![0.0f32; pix];
    let mut resolved_mask = vec![false; pix];
    let mut resolved_count = 0u32;

    let shell = field.current_shell;

    for i in 0..pix {
        let cell = &field.cells[i];
        if noise_admitted_at_shell(&cell.noise_color, shell)
            && cell.noise_color != NoiseColor::White
        {
            // Constructive interference: confidence-weighted average
            let total_conf: f32 = cell.confidence.iter().sum();
            if total_conf > 0.0 {
                let depth: f32 = cell
                    .observations
                    .iter()
                    .zip(cell.confidence.iter())
                    .map(|(d, c)| d * c)
                    .sum::<f32>()
                    / total_conf;
                resolved_depth[i] = depth;
                resolved_mask[i] = true;
                resolved_count += 1;
            }
        }
    }

    let resolution_gain = if pix > 0 {
        resolved_count as f32 / pix as f32
    } else {
        0.0
    };

    UpresolutionResult {
        resolved_depth,
        resolved_mask,
        resolution_gain,
    }
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_standing_wave_detection() {
        let mut cell = PhyleTemporalCell::new();
        cell.ingest(TritonPhase::Past, 0.5, 1.0, 0.8);
        cell.ingest(TritonPhase::Present, 0.5, 1.0, 0.8);
        cell.ingest(TritonPhase::Future, 0.5, 1.0, 0.8);
        cell.compute_diffs();
        cell.classify_noise(0.001, 0.01);
        assert_eq!(cell.noise_color, NoiseColor::StandingWave);
        assert_eq!(cell.phase_variance, 0.0);
        assert_eq!(cell.second_degree_diff, 0.0);
        assert!(cell.try_resolve(0));
        assert_eq!(cell.fused_depth, 0.5);
    }

    #[test]
    fn test_noise_detection() {
        let mut cell = PhyleTemporalCell::new();
        cell.ingest(TritonPhase::Past, 0.1, 1.0, 0.3);
        cell.ingest(TritonPhase::Present, 0.9, 1.0, 0.7);
        cell.ingest(TritonPhase::Future, 0.2, 1.0, 0.1);
        cell.compute_diffs();
        cell.classify_noise(0.001, 0.01);
        assert_eq!(cell.noise_color, NoiseColor::White);
        assert!(!cell.try_resolve(0));
        assert!(!cell.try_resolve(1));
    }

    #[test]
    fn test_pink_resolution() {
        let mut cell = PhyleTemporalCell::new();
        // Small variance = pink
        cell.ingest(TritonPhase::Past, 0.50, 0.9, 0.6);
        cell.ingest(TritonPhase::Present, 0.51, 0.8, 0.6);
        cell.ingest(TritonPhase::Future, 0.49, 0.95, 0.6);
        cell.compute_diffs();
        cell.classify_noise(0.001, 0.01);
        assert_eq!(cell.noise_color, NoiseColor::Pink);
        assert!(cell.try_resolve(0));
    }

    #[test]
    fn test_triton_window_pipeline() {
        let mut field = PhyleTemporalDepthField::new(2, 2);
        let depth = vec![0.5; 4];
        let conf = vec![1.0; 4];
        let deblur = vec![0.8; 4];

        // Ingest 3 frames (one triton window)
        let r1 = field.ingest_frame(&depth, &conf, &deblur).unwrap();
        assert!(r1.is_none());
        let r2 = field.ingest_frame(&depth, &conf, &deblur).unwrap();
        assert!(r2.is_none());
        let r3 = field.ingest_frame(&depth, &conf, &deblur).unwrap();
        assert!(r3.is_some());

        let result = r3.unwrap();
        assert_eq!(result.window_index, 0);
        assert_eq!(result.standing_wave_count, 4);
        assert_eq!(result.shell, 0);
        assert_eq!(field.triton_windows_completed, 1);
    }

    #[test]
    fn test_shell_promotion() {
        let mut field = PhyleTemporalDepthField::new(1, 1);
        let depth = vec![0.5];
        let conf = vec![1.0];
        let deblur = vec![0.8];

        // Shell 0 needs 3 windows (3^1 = 3) to promote to shell 1
        for _ in 0..9 {
            field.ingest_frame(&depth, &conf, &deblur).unwrap();
        }
        assert_eq!(field.current_shell, 1);
    }

    #[test]
    fn test_rotation_direction_stride_seven() {
        let mut field = PhyleTemporalDepthField::new(1, 1);
        assert_eq!(field.rotation_direction(), 0);
        field.triton_windows_completed = 1;
        assert_eq!(field.rotation_direction(), 7);
        field.triton_windows_completed = 2;
        assert_eq!(field.rotation_direction(), 14);
        field.triton_windows_completed = 3;
        assert_eq!(field.rotation_direction(), 21);
        field.triton_windows_completed = 4;
        assert_eq!(field.rotation_direction(), (28) % 27); // = 1
        assert_eq!(field.rotation_direction(), 1);
    }

    #[test]
    fn test_spectral_budget() {
        assert_eq!(spectral_budget(0), 1);
        assert_eq!(spectral_budget(1), 2);
        assert_eq!(spectral_budget(2), 3);
        assert!(noise_admitted_at_shell(&NoiseColor::Pink, 0));
        assert!(!noise_admitted_at_shell(&NoiseColor::Brown, 0));
        assert!(noise_admitted_at_shell(&NoiseColor::Brown, 1));
    }

    #[test]
    fn test_temporal_deblur_classify() {
        let mut field = PhyleTemporalDepthField::new(2, 1);
        // Pixel 0: stable high deblur = real edge
        field.cells[0].deblur_admission = [0.8, 0.8, 0.8];
        field.cells[0].deblur_variance = 0.0;
        // Pixel 1: unstable deblur = noise artifact
        field.cells[1].deblur_admission = [0.9, 0.1, 0.8];
        field.cells[1].deblur_variance = 0.12;

        let result = temporal_deblur_classify(&field);
        assert!(result.stable_edges[0] > 0.5);
        assert_eq!(result.edge_confidence[0], 1.0);
        assert!(result.unstable_noise[1] > 0.05);
        assert_eq!(result.edge_confidence[1], 0.0);
    }

    #[test]
    fn test_frames_at_shell() {
        let field = PhyleTemporalDepthField::new(1, 1);
        assert_eq!(field.frames_at_current_shell(), 3); // shell 0
    }
}
